import{_ as t,o,c as r,a2 as i}from"./chunks/framework.BZO4qERu.js";const h=JSON.parse('{"title":"PaperSeek 在线体验版使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"online-demo.md","filePath":"online-demo.md","lastUpdated":1783267649000}'),a={name:"online-demo.md"};function d(n,e,l,c,s,p){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="paperseek-在线体验版使用说明" tabindex="-1">PaperSeek 在线体验版使用说明 <a class="header-anchor" href="#paperseek-在线体验版使用说明" aria-label="Permalink to &quot;PaperSeek 在线体验版使用说明&quot;">​</a></h1><p>在线体验版用于直接试用完整 Web UI，不需要自己部署服务。它与开源自托管版共享主要检索核心，但账号、云端历史、在线模型服务和额度管理只属于在线版。</p><p>在线体验地址：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.paperseek.xyz/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="三种使用模式" tabindex="-1">三种使用模式 <a class="header-anchor" href="#三种使用模式" aria-label="Permalink to &quot;三种使用模式&quot;">​</a></h2><p>配置区提供三个互斥模式，展开一个栏目时会折叠另外两个栏目。</p><h3 id="paperseek-service" tabindex="-1">PaperSeek Service <a class="header-anchor" href="#paperseek-service" aria-label="Permalink to &quot;PaperSeek Service&quot;">​</a></h3><p><code>PaperSeek Service</code> 是注册用户的轻量试用模式。用户登录并完成邮箱验证后即可使用，不需要自己填写模型 Key 或已纳入服务范围的数据源 Key。</p><ul><li>默认每日额度为 20 次成功检索；失败不消耗额度。</li><li>当前支持 OpenAlex、arXiv、Semantic Scholar、PubMed、Crossref 和计算机顶会检索。</li><li>OpenAlex、Semantic Scholar、PubMed 和 Crossref 在 PaperSeek Service 范围内由在线服务处理；Crossref 不需要 API Key。</li><li><code>Auto</code> 模式会自动选择当前最合适的模型，默认使用本地 hashing sparse cosine 和 RRF 预重排。</li><li><code>Custom</code> 模式允许用户选择在线服务提供的请求模型、Embedding 模型和预重排方式；前端只显示模型名，后端负责映射到对应服务商。</li><li>免费模型仅面向个人注册用户提供轻量使用支持。PaperSeek 是个人维护的开源项目，免费额度有限且不做 SLA 稳定性保证；重度使用请部署开源版并填写自己的 API key。</li><li>个人用户需要提高额度时，请提供姓名、单位、用途和 UID（右上角账户信息页的 Signed-in account 栏目）发送至 <code>paperseek-community@outlook.com</code>。</li></ul><h3 id="third-party-service" tabindex="-1">Third-party Service <a class="header-anchor" href="#third-party-service" aria-label="Permalink to &quot;Third-party Service&quot;">​</a></h3><p><code>Third-party Service</code> 使用用户自己的第三方推理额度，当前支持 ModelScope、OpenRouter 和 Hugging Face。</p><ul><li>ModelScope：必须通过 ModelScope 登录，或在已登录账号中连接 ModelScope 身份。ModelScope 官方文档也会写作 API Inference；本文中的 API-Inference 与 API Inference 指同一服务。PaperSeek 使用当前会话中的 ModelScope provider token 发起请求，不会保存该 token。使用前请确认 ModelScope 账号已绑定阿里云账号并完成实名认证。在线版 ModelScope OAuth 默认使用 <code>openid profile</code>，不要额外添加 <code>email</code>、<code>api-inference</code> 或未在魔搭 OAuth 应用中启用的 scope，否则可能出现 <code>invalid_scope</code>。</li><li>OpenRouter：点击授权后使用浏览器中的 OpenRouter PKCE 会话，不走 Supabase OAuth。<code>Free Model Automatic</code> 会拉取当前可用的免费模型，并按 OpenRouter 模型元数据优先选择 text 能力模型；也可以填写自定义模型。</li><li>Hugging Face：通过 Supabase custom OAuth/OIDC 连接 Hugging Face，scope 包含 <code>openid profile email inference-api</code>。PaperSeek 使用 Hugging Face Router 的 OpenAI-compatible endpoint <code>https://router.huggingface.co/v1</code> 代表用户发起推理请求。</li><li>ModelScope 的 Embedding 预重排使用同一 provider token 调用 <code>Qwen/Qwen3-Embedding-8B</code>，失败时回退到 <code>Qwen/Qwen3-Embedding-4B</code>。OpenRouter 和 Hugging Face 的 Automatic 模式只使用可明确识别的免费模型；如果没有可用的免费 embedding 或 rerank 模型，会回退到本地 hashing embedding、BM25 和 RRF。</li><li>第三方服务的可用额度、并发和模型可用性以对应平台实际接口为准。</li></ul><h3 id="bring-your-own-key" tabindex="-1">Bring your own Key <a class="header-anchor" href="#bring-your-own-key" aria-label="Permalink to &quot;Bring your own Key&quot;">​</a></h3><p><code>Bring your own Key</code> 适合已有模型服务 API Key 的用户，也可以理解为 bring your own provider keys (BYOK) 模式。</p><ul><li>未登录用户也可以使用。</li><li>默认 provider 是 OpenAI，也可以选择 DeepSeek、中国科技云、ModelScope API-Inference、Ollama、OpenRouter、NVIDIA NIM 或自定义 OpenAI-compatible 服务。</li><li>API Key、Base URL、模型和运行参数只用于当前浏览器会话。</li><li>未登录用户使用 OpenAlex 检索时必须填写自己的 OpenAlex Key；登录用户可直接使用 OpenAlex，也可在高级设置中填写自己的 Key。</li><li>BYOK 模式不使用 PaperSeek Service 免费额度，也不消耗 Third-party Service 的 OAuth/session token。</li><li>未登录用户不能使用云端历史记录。</li></ul><h2 id="账号和权限" tabindex="-1">账号和权限 <a class="header-anchor" href="#账号和权限" aria-label="Permalink to &quot;账号和权限&quot;">​</a></h2><p>在线版使用 Supabase Auth 管理账号和云端历史。登录方式包括邮箱、GitHub、ModelScope 和 Hugging Face。GitHub、ModelScope 与 Hugging Face 是同一账号模型下的 OAuth 身份；PaperSeek Service 需要已验证邮箱的 PaperSeek 账号。OpenRouter 授权保存在当前浏览器会话中，不作为 Supabase 登录身份。</p><p>账户面板会显示当前账号的一览表，包括邮箱账号、GitHub 登录、ModelScope 登录、Hugging Face 登录、第三方推理授权和 PaperSeek Service 权限。</p><table tabindex="0"><thead><tr><th>功能</th><th>未登录</th><th>邮箱/GitHub 登录</th><th>已连接 ModelScope 或 Hugging Face</th><th>OpenRouter 已授权</th></tr></thead><tbody><tr><td>Bring your own Key</td><td>支持，需要自填模型 Key；OpenAlex 需自填 Key</td><td>支持</td><td>支持</td><td>支持；OpenRouter 仅用于本次浏览器会话</td></tr><tr><td>PaperSeek Service</td><td>不支持</td><td>支持，每日成功检索额度</td><td>支持，每日成功检索额度</td><td>不支持，除非同时登录 PaperSeek 账号</td></tr><tr><td>Third-party Service</td><td>OpenRouter 授权后可使用 OpenRouter</td><td>连接对应第三方后可使用</td><td>支持对应平台授权</td><td>支持 OpenRouter 会话授权</td></tr><tr><td>云端 History</td><td>不支持</td><td>支持</td><td>支持</td><td>不支持，除非同时登录 PaperSeek 账号</td></tr></tbody></table><p>公共电脑或共享浏览器使用后请退出登录。历史记录按登录账号隔离，不按 IP 地址隔离。</p><h2 id="推荐流程" tabindex="-1">推荐流程 <a class="header-anchor" href="#推荐流程" aria-label="Permalink to &quot;推荐流程&quot;">​</a></h2><ol><li>进入 <a href="https://www.paperseek.xyz/" target="_blank" rel="noreferrer">paperseek.xyz</a>。</li><li>如需中文界面，点击顶部状态栏中的 <code>中文</code>。</li><li>选择使用模式： <ul><li>想快速试用：登录后选择 <code>PaperSeek Service</code>。</li><li>想使用自己的 ModelScope、OpenRouter 或 Hugging Face 推理额度：选择 <code>Third-party Service</code> 并连接对应服务。</li><li>想使用自己的模型服务、本地 Ollama 或完整数据源能力：选择 <code>Bring your own Key</code>。</li></ul></li><li>输入 Research Question。</li><li>在 Research Question 下方选择数据源和 Source Filter。OpenAlex、WoS、arXiv 使用各自可靠的原生过滤；其他数据源显示 <code>Field/context hint</code> 文本提示。</li><li>点击 <code>Check Config</code> 检查配置。失败时页面会弹出问题列表，并提示需要修复的字段。</li><li>点击 <code>Run Search</code> 开始检索。</li><li>在工作流 03 阶段查看候选准备、多路召回、Embedding 相似度、RRF 融合、LLM 批量打分、引用扩展重排和摘要补全等子步骤进度。</li><li>在 <code>Results</code> 查看、筛选和勾选论文，并导出 CSV。</li><li>在 <code>Citation Map</code> 查看 OpenAlex 引用扩展形成的引用关系图。</li><li>登录用户可在 <code>History</code> 回看云端历史检索记录。</li></ol><p><code>TARGET_MAX</code> 用于指导检索式收窄或放宽，不是最终展示硬上限。在线版默认最多把 256 条预重排候选交给 LLM 打分；最终结果少于 50 条时全部展示，结果较多时至少展示前 50 条，如果 5 分及以上候选超过 50 条，则展示全部高分候选。</p><h2 id="与开源自托管版的区别" tabindex="-1">与开源自托管版的区别 <a class="header-anchor" href="#与开源自托管版的区别" aria-label="Permalink to &quot;与开源自托管版的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>在线体验版</th><th>开源自托管版</th></tr></thead><tbody><tr><td>登录</td><td>使用 Supabase 账号系统；PaperSeek Service 和 History 需要登录</td><td>默认不需要登录</td></tr><tr><td>模型调用</td><td>PaperSeek Service 可使用站点免费额度；Third-party Service 使用用户第三方授权；也可 BYOK</td><td>使用你自己配置的 LLM API Key</td></tr><tr><td>OpenAlex Key</td><td>登录用户可直接使用；未登录 BYOK 模式需自填 OpenAlex Key</td><td>可匿名访问或自己配置 key</td></tr><tr><td>Source Filter</td><td>页面选择，随本次搜索提交</td><td>页面选择、CLI 参数或 <code>DISCIPLINE_FIELDS</code> 环境变量</td></tr><tr><td>历史记录</td><td>登录后保存到云端 Supabase 数据库</td><td>默认保存到本地 SQLite</td></tr><tr><td>适用场景</td><td>快速体验、轻量检索、临时试用</td><td>私有部署、长期使用、可控配置</td></tr></tbody></table><h2 id="english-summary" tabindex="-1">English Summary <a class="header-anchor" href="#english-summary" aria-label="Permalink to &quot;English Summary&quot;">​</a></h2><p>The hosted PaperSeek edition lets users try the full Web UI without deploying their own server. It shares the main search core with the open-source edition, while account handling, hosted history, hosted model service, and quota management belong to the hosted service.</p><p>The hosted configuration panel has three mutually exclusive modes:</p><ul><li><code>PaperSeek Service</code>: requires sign-in and a verified email. PaperSeek provides hosted model routes and managed access to the supported sources in this mode. It currently exposes OpenAlex, arXiv, Semantic Scholar, PubMed, Crossref, and computer science top-conference search. The default quota is 20 successful searches per day; failed searches do not consume quota. Auto mode keeps embedding local and pre-ranking on RRF, while Custom mode lets users choose hosted request, embedding, and rerank models.</li><li><code>Third-party Service</code>: uses the user&#39;s own third-party inference quota. ModelScope uses the signed-in user&#39;s API-Inference provider token; OpenRouter uses a browser PKCE session and can automatically try current free text models; Hugging Face uses Supabase custom OAuth/OIDC with the <code>inference-api</code> scope and the OpenAI-compatible Router endpoint. Automatic embedding/rerank only uses clearly identifiable free models and otherwise falls back to local hashing, BM25, and RRF.</li><li><code>Bring your own Key</code>: can be used without sign-in. Users follow the bring your own provider keys (BYOK) pattern, including their own model API key and, when anonymous, their own OpenAlex key for OpenAlex searches.</li></ul><p>Hosted history is isolated by authenticated user and does not store raw user model keys, OpenAlex keys, ModelScope provider tokens, OpenRouter session keys, or Hugging Face provider tokens. Sign out after using PaperSeek on a shared computer.</p>',30)])])}const S=t(a,[["render",d]]);export{h as __pageData,S as default};
